  1→/**
  2→ * Telegram UI helpers — message formatting, splitting, ASK keyboards,
  3→ * file sending, and token extraction for SEND_FILE / SCHEDULE / ASK.
  4→ * Extracted from index.ts to reduce its size.
  5→ */
  6→import { InlineKeyboard, Context, InputFile } from "grammy";
  7→import path from "node:path";
  8→import { stat } from "node:fs/promises";
  9→import { config } from "./config.js";
 10→import type { ChatSession } from "./sessionManager.js";
 11→import { toolPrefixLines } from "./sessionManager.js";
 12→import { transform as transformReplyTokens } from "./observerTransformer.js";
 13→import type { Recurrence } from "./recurrence.js";
 14→import { markdownToHtml } from "./format-html.js";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Constants
 18→// ---------------------------------------------------------------------------
 19→const CODE_PLACEHOLDER_RE = /\u0000CODE(\d+)\u0000/g;
 20→const SEND_FILE_RE = /<<SEND_FILE:\s*([^>\r\n]+?)\s*>>/g;
 21→const SCHEDULE_RE = /<<SCHEDULE:\s*([^>\r\n]+?)\s*>>/g;
 22→const SCHEDULE_PROMPT_MAX = 1000;
 23→const SCHEDULE_MAX_PER_MSG = 3;
 24→const ASK_RE = /<<ASK:\s*([^>\r\n]+?)\s*>>/g;
 25→const ASK_ID_RE = /^[a-zA-Z0-9_-]{1,32}$/;
 26→const ASK_KEY_RE = /^[a-zA-Z0-9_-]{1,20}$/;
 27→const ASK_LABEL_MAX = 40;
 28→const ASK_LABEL_SOFT = 20;
 29→export const IMG_EXT = new Set([".png", ".jpg", ".jpeg", ".gif", ".webp", ".bmp"]);
 30→export const TG_MAX = 3900;
 31→
 32→// ---------------------------------------------------------------------------
 33→// Interfaces
 34→// ---------------------------------------------------------------------------
 35→export interface AskOption {
 36→  key: string;
 37→  label: string;
 38→  recommended: boolean;
 39→}
 40→
 41→export interface AskEntry {
 42→  questionId: string;
 43→  options: AskOption[];
 44→}
 45→
 46→export interface ScheduleTokenEntry {
 47→  runAt: number;
 48→  prompt: string;
 49→  whenLabel: string;
 50→  recurrence?: Recurrence;
 51→}
 52→
 53→export interface PendingSchedule {
 54→  userId: number;
 55→  kind: "add" | "at" | "every" | "daily";
 56→  time: string;
 57→  createdAt: number;
 58→}
 59→
 60→/** Parsers injected by caller to avoid circular deps */
 61→export interface ScheduleParsers {
 62→  parseDuration: (s: string) => number | null;
 63→  parseAbsoluteTime: (s: string) => Date | null;
 64→  parseRecurrence: (s: string) => Recurrence | null;
 65→  computeNextRunAt: (r: Recurrence, after: number) => number | null;
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Code-block masking
 70→// ---------------------------------------------------------------------------
 71→export function maskCodeRegions(text: string): { masked: string; restore: (s: string) => string } {
 72→  const slots: string[] = [];
 73→  const masked = text.replace(/```[\s\S]*?```|`[^`\n]*`/g, (m) => {
 74→    const idx = slots.length;
 75→    slots.push(m);
 76→    return `\u0000CODE${idx}\u0000`;
 77→  });
 78→  const restore = (s: string) =>
 79→    s.replace(CODE_PLACEHOLDER_RE, (_m, i: string) => slots[Number(i)] ?? "");
 80→  return { masked, restore };
 81→}
 82→
 83→// ---------------------------------------------------------------------------
 84→// SEND_FILE token extraction
 85→// ---------------------------------------------------------------------------
 86→export function extractSendFileTokens(text: string): { text: string; paths: string[] } {
 87→  if (!text) return { text: "", paths: [] };
 88→  const paths: string[] = [];
 89→  const { masked, restore } = maskCodeRegions(text);
 90→  const stripped = masked.replace(SEND_FILE_RE, (_m, p: string) => {
 91→    paths.push(p.trim());
 92→    return "";
 93→  });
 94→  const cleaned = restore(stripped).replace(/\n{3,}/g, "\n\n").trim();
 95→  return { text: cleaned, paths };
 96→}
 97→
 98→// ---------------------------------------------------------------------------
 99→// SCHEDULE token extraction
100→// ---------------------------------------------------------------------------
101→export function extractScheduleTokens(
102→  text: string,
103→  parsers: ScheduleParsers,
104→): { text: string; entries: ScheduleTokenEntry[] } {
105→  if (!text) return { text: "", entries: [] };
106→  const entries: ScheduleTokenEntry[] = [];
107→  const { masked, restore } = maskCodeRegions(text);
108→  const stripped = masked.replace(SCHEDULE_RE, (match, inner: string) => {
109→    if (entries.length >= SCHEDULE_MAX_PER_MSG) return match;
110→    const pipe = inner.indexOf("|");
111→    if (pipe <= 0) return match;
112→    const timeRaw = inner.slice(0, pipe).trim();
113→    let prompt = inner.slice(pipe + 1).trim();
114→    if (!prompt) return match;
115→    if (prompt.length > SCHEDULE_PROMPT_MAX) {
116→      prompt = prompt.slice(0, SCHEDULE_PROMPT_MAX);
117→    }
118→    const now = Date.now();
119→    const recurrence = parsers.parseRecurrence(timeRaw);
120→    if (recurrence) {
121→      const firstRunAt = parsers.computeNextRunAt(recurrence, now - 1);
122→      if (firstRunAt === null) return match;
123→      entries.push({ runAt: firstRunAt, prompt, whenLabel: timeRaw, recurrence });
124→      return "";
125→    }
126→    let runAt: number | null = null;
127→    const dur = parsers.parseDuration(timeRaw);
128→    if (dur !== null) {
129→      runAt = now + dur;
130→    } else {
131→      const dt = parsers.parseAbsoluteTime(timeRaw);
132→      if (dt && dt.getTime() > now) runAt = dt.getTime();
133→    }
134→    if (runAt === null) return match;
135→    entries.push({ runAt, prompt, whenLabel: timeRaw });
136→    return "";
137→  });
138→  const cleaned = restore(stripped).replace(/\n{3,}/g, "\n\n").trim();
139→  return { text: cleaned, entries };
140→}
141→
142→// ---------------------------------------------------------------------------
143→// ASK token extraction & keyboard
144→// ---------------------------------------------------------------------------
145→export function extractAskTokens(text: string): { text: string; asks: AskEntry[] } {
146→  if (!text) return { text: "", asks: [] };
147→  const asks: AskEntry[] = [];
148→  const seenIds = new Set<string>();
149→  const { masked, restore } = maskCodeRegions(text);
150→  const stripped = masked.replace(ASK_RE, (match, inner: string) => {
151→    const entry = parseAskInner(inner);
152→    if (!entry) return match;
153→    if (seenIds.has(entry.questionId)) {
154→      const idx = asks.findIndex((a) => a.questionId === entry.questionId);
155→      if (idx >= 0) asks.splice(idx, 1);
156→    }
157→    seenIds.add(entry.questionId);
158→    asks.push(entry);
159→    return "";
160→  });
161→  const cleaned = restore(stripped).replace(/\n{3,}/g, "\n\n").trim();
162→  return { text: cleaned, asks };
163→}
164→
165→function parseAskInner(inner: string): AskEntry | null {
166→  const reject = (reason: string): null => {
167→    const preview = inner.length > 80 ? `${inner.slice(0, 77)}...` : inner;
168→    console.warn(`[ASK] malformed token rejected: ${reason} | inner="${preview}"`);
169→    return null;
170→  };
171→  const parts = inner.split("|").map((s) => s.trim());
172→  if (parts.length < 2) return reject("need at least question_id + 1 option");
173→  const questionId = parts[0];
174→  if (!ASK_ID_RE.test(questionId)) {
175→    return reject(
176→      `question_id "${questionId}" invalid (need [a-zA-Z0-9_-]{1,32}, got length ${questionId.length})`
177→    );
178→  }
179→  const options: AskOption[] = [];
180→  const keys = new Set<string>();
181→  let recommendedCount = 0;
182→  for (const raw of parts.slice(1)) {
183→    if (!raw) continue;
184→    let spec = raw;
185→    let recommended = false;
186→    if (spec.startsWith("*")) {
187→      recommended = true;
188→      spec = spec.slice(1);
189→    }
190→    const eq = spec.indexOf("=");
191→    if (eq <= 0) return reject(`option "${raw}" missing "key=label"`);
192→    const key = spec.slice(0, eq).trim();
193→    const label = spec.slice(eq + 1).trim();
194→    if (!ASK_KEY_RE.test(key)) {
195→      return reject(
196→        `key "${key}" invalid (need [a-zA-Z0-9_-]{1,20}, got length ${key.length})`
197→      );
198→    }
199→    if (!label) return reject(`key "${key}" has empty label`);
200→    if (label.length > ASK_LABEL_SOFT && label.length <= ASK_LABEL_MAX) {
201→      console.warn(
202→        `[ASK] label soft cap exceeded (got ${label.length}, soft ${ASK_LABEL_SOFT}): key="${key}" label="${label}"`,
203→      );
204→    }
205→    if (label.length > ASK_LABEL_MAX) {
206→      return reject(
207→        `key "${key}" label too long (got ${label.length}, max ${ASK_LABEL_MAX}): "${label}"`
208→      );
209→    }
210→    if (keys.has(key)) return reject(`duplicate key "${key}"`);
211→    keys.add(key);
212→    if (recommended && recommendedCount > 0) recommended = false;
213→    if (recommended) recommendedCount++;
214→    options.push({ key, label, recommended });
215→  }
216→  if (options.length < 1) return reject("no valid options");
217→  if (options.length > 8) return reject(`too many options (got ${options.length}, max 8)`);
218→  return { questionId, options };
219→}
220→
221→export function buildAskKeyboard(asks: AskEntry[]): InlineKeyboard | null {
222→  if (!asks.length) return null;
223→  const kb = new InlineKeyboard();
224→  for (let ai = 0; ai < asks.length; ai++) {
225→    const entry = asks[ai];
226→    const rows = layoutOptions(entry.options);
227→    for (const row of rows) {
228→      for (const opt of row) {
229→        const label = opt.recommended ? `⭐ ${opt.label}` : opt.label;
230→        kb.text(label, `A:${entry.questionId}:${opt.key}`);
231→      }
232→      kb.row();
233→    }
234→    const rec = entry.options.find((o) => o.recommended);
235→    if (rec) {
236→      kb.text("👉 照你的建議", `A:${entry.questionId}:${rec.key}`).row();
237→    }
238→  }
239→  return kb;
240→}
241→
242→export function layoutOptions(options: AskOption[]): AskOption[][] {
243→  const n = options.length;
244→  if (n <= 3) return [options];
245→  if (n <= 6) {
246→    const perRow = Math.ceil(n / 2);
247→    return [options.slice(0, perRow), options.slice(perRow)];
248→  }
249→  const perRow = Math.ceil(n / 2);
250→  return [options.slice(0, perRow), options.slice(perRow)];
251→}
252→
253→// In-memory registry: message_id -> ASK entries on that message.
254→export const askRegistry = new Map<number, AskEntry[]>();
255→
256→export async function replyWithAsk(ctx: Context, text: string): Promise<void> {
257→  const { text: displayBody, asks } = extractAskTokens(text);
258→  const body = displayBody || text;
259→  const keyboard = buildAskKeyboard(asks);
260→  const msg = await ctx.reply(body, keyboard ? { reply_markup: keyboard } : {});
261→  if (keyboard && msg?.message_id !== undefined) {
262→    askRegistry.set(msg.message_id, asks);
263→  }
264→}
265→
266→// ---------------------------------------------------------------------------
267→// askTimeKeyToWire / describePendingSchedule
268→// ---------------------------------------------------------------------------
269→export function askTimeKeyToWire(kind: PendingSchedule["kind"], key: string): string | null {
270→  if (kind === "add" || kind === "every") {
271→    return /^\d+(s|m|h|d)$/.test(key) ? key : null;
272→  }
273→  const mDirect = /^(\d{2})(\d{2})$/.exec(key);
274→  if (mDirect) return `${mDirect[1]}:${mDirect[2]}`;
275→  if (kind === "at") {
276→    const mTmr = /^tmr_(\d{2})(\d{2})$/.exec(key);
277→    if (mTmr) return `tomorrow ${mTmr[1]}:${mTmr[2]}`;
278→  }
279→  return null;
280→}
281→
282→export function describePendingSchedule(kind: PendingSchedule["kind"], time: string): string {
283→  switch (kind) {
284→    case "add":   return `${time} 後（一次性）`;
285→    case "at":    return `${time}（一次性）`;
286→    case "every": return `每 ${time}`;
287→    case "daily": return `每天 ${time}`;
288→  }
289→}
290→
291→// ---------------------------------------------------------------------------
292→// sendFilesByPaths / isUnderAllowedRoot
293→// ---------------------------------------------------------------------------
294→export async function sendFilesByPaths(ctx: Context, paths: string[]): Promise<number> {
295→  if (paths.length === 0) return 0;
296→  const chatId = ctx.chat?.id;
297→  const seen = new Set<string>();
298→  let sent = 0;
299→  for (const raw of paths) {
300→    const abs = path.resolve(raw);
301→    const key = abs.toLowerCase();
302→    if (seen.has(key)) continue;
303→    seen.add(key);
304→    if (!isUnderAllowedRoot(abs)) {
305→      console.log(`[chat ${chatId}] SEND_FILE: refused (not under allowed roots): ${abs}`);
306→      continue;
307→    }
308→    try {
309→      const st = await stat(abs);
310→      if (!st.isFile()) {
311→        console.log(`[chat ${chatId}] SEND_FILE: skip (not a regular file): ${abs}`);
312→        continue;
313→      }
314→      const ext = path.extname(abs).toLowerCase();
315→      // .md → .txt display name: Telegram in-app viewer 對 .md UTF-8 偵測不可靠，中文會亂碼
316→      const displayName = ext === ".md"
317→        ? path.basename(abs, ext) + ".txt"
318→        : undefined;
319→      const asPhoto = IMG_EXT.has(ext) && ext !== ".png" && st.size <= 10 * 1024 * 1024;
320→      if (asPhoto) {
321→        try {
322→          await ctx.replyWithPhoto(new InputFile(abs));
323→          console.log(`[chat ${chatId}] SEND_FILE: sent photo (${st.size}B): ${abs}`);
324→        } catch (err) {
325→          console.warn(`[chat ${chatId}] SEND_FILE: photo rejected, fallback to document:`, (err as Error).message);
326→          await ctx.replyWithDocument(new InputFile(abs, displayName));
327→        }
328→      } else {
329→        await ctx.replyWithDocument(new InputFile(abs, displayName));
330→        console.log(`[chat ${chatId}] SEND_FILE: sent document (${st.size}B): ${abs}`);
331→      }
332→      sent++;
333→    } catch (err) {
334→      console.warn(`[chat ${chatId}] SEND_FILE: failed ${abs} — ${(err as Error).message}`);
335→    }
336→  }
337→  return sent;
338→}
339→
340→export function isUnderAllowedRoot(abs: string): boolean {
341→  const roots = [config.sessionCwd, ...config.sendFileRoots];
342→  const normAbs = path.resolve(abs).toLowerCase();
343→  return roots.some((root) => {
344→    const r = path.resolve(root).toLowerCase().replace(/[\\/]+$/, "");
345→    if (normAbs === r) return true;
346→    return normAbs.startsWith(r + "\\") || normAbs.startsWith(r + "/");
347→  });
348→}
349→
350→// ---------------------------------------------------------------------------
351→// splitForTelegram
352→// ---------------------------------------------------------------------------
353→export function splitForTelegram(text: string, max = TG_MAX): string[] {
354→  if (text.length <= max) return [text];
355→  const raw: string[] = [];
356→  let rest = text;
357→  while (rest.length > max) {
358→    let cut = rest.lastIndexOf("\n\n", max);
359→    if (cut < max * 0.5) cut = rest.lastIndexOf("\n", max);
360→    if (cut < max * 0.5) cut = rest.lastIndexOf(" ", max);
361→    if (cut <= 0) cut = max;
362→    raw.push(rest.slice(0, cut));
363→    rest = rest.slice(cut).replace(/^[\n ]+/, "");
364→  }
365→  if (rest.length) raw.push(rest);
366→
367→  const fenceRe = /^```([^\n`]*)\s*$/;
368→  const out: string[] = [];
369→  let openLang = "";
370→  for (let i = 0; i < raw.length; i++) {
371→    let piece = raw[i];
372→    if (openLang !== "") {
373→      piece = "```" + openLang + "\n" + piece;
374→    }
375→    const lines = piece.split("\n");
376→    let inside = false;
377→    let lang = "";
378→    for (const line of lines) {
379→      const m = line.match(fenceRe);
380→      if (!m) continue;
381→      if (!inside) {
382→        inside = true;
383→        lang = m[1] ?? "";
384→      } else {
385→        inside = false;
386→        lang = "";
387→      }
388→    }
389→    if (inside && i < raw.length - 1) {
390→      piece = piece + (piece.endsWith("\n") ? "" : "\n") + "```";
391→      openLang = lang;
392→    } else {
393→      openLang = "";
394→    }
395→    out.push(piece);
396→  }
397→  return out;
398→}
399→
400→// ---------------------------------------------------------------------------
401→// renderReply (streaming display)
402→// ---------------------------------------------------------------------------
403→export interface RenderResult {
404→  content: string;
405→  parseMode: "HTML" | undefined;
406→}
407→
408→export function renderReply(
409→  session: ChatSession,
410→  done: boolean,
411→  parsers: ScheduleParsers,
412→): RenderResult {
413→  const toolLines = toolPrefixLines(session);
414→  const tools = toolLines.length ? toolLines.join("\n") + "\n\n" : "";
415→  const cursor = done ? "" : " ▍";
416→  const emptyFallback = () => {
417→    if (!done) return session.thinkingBuffer ? "" : "Thinking…";
418→    const n = session.toolTimeline.length;
419→    return n > 0 ? `(no text yet — ${n} tool call${n === 1 ? "" : "s"} so far)` : "(no response)";
420→  };
421→
422→  // Show thinking progress during streaming (hide when done)
423→  let thinkingBlock = "";
424→  if (!done && session.thinkingBuffer) {
425→    // Show last ~200 chars of thinking as blockquote
426→    const t = session.thinkingBuffer;
427→    const preview = t.length > 200 ? "…" + t.slice(-200) : t;
428→    thinkingBlock = "💭 " + preview.split("\n").join("\n> ") + "\n\n";
429→  }
430→
431→  const raw = session.buffer || emptyFallback();
432→  const stripped = transformReplyTokens(raw, parsers).text;
433→  let body = stripped || emptyFallback();
434→  if (body.length > TG_MAX) {
435→    body = "…" + body.slice(-TG_MAX);
436→  }
437→
438→  const plain = tools + thinkingBlock + body + cursor;
439→  const { html } = markdownToHtml(plain);
440→  return { content: html, parseMode: "HTML" };
441→}
