 96→// on Telegram. Same cap applied to SKILL_USED and RESTART for policy
 97→// consistency.
 98→export const BALANCED_REASON_MAX = 500;
 99→
100→// ───────────────────────────────────────────────────────────────────────
101→// Payload interfaces
102→// ───────────────────────────────────────────────────────────────────────
103→export interface AskOption {
104→  key: string;
105→  label: string;
106→  recommended: boolean;
107→}
108→
109→export interface AskEntry {
110→  questionId: string;
111→  options: AskOption[];
112→}
113→
114→export interface ScheduleTokenEntry {
115→  runAt: number;
116→  prompt: string;
117→  whenLabel: string;
118→  recurrence?: Recurrence;
119→}
120→
121→export interface SkillUsageEntry {
122→  name: string;
123→  reason: string;
124→}
125→
126→export interface GoalDoneEntry {
127→  reason: string;
128→}
129→
130→/** Payload of a valid <<RESTART:reason>> token. C3 (2026-05-02).
131→ *
132→ * `reason` is trimmed but not otherwise validated here — the guardrail
133→ * layer (goalStore.markRestart + runPrompt) decides whether an empty
134→ * reason is allowed. We just extract; empty reasons still produce an
135→ * entry so the runPrompt layer can surface a proper "empty-reason"
136→ * warning to the user instead of the token silently staying in text. */
137→export interface RestartTokenEntry {
138→  reason: string;
139→}
140→
141→/** Payload of a valid <<SKILL_PROPOSE:name|reason>> token. Agent proposes
142→ *  writing a skill; bridge shows an ASK button for user confirmation. */
143→export interface SkillProposeEntry {
144→  name: string;
145→  reason: string;
146→}
147→
148→/** Payload of a valid <<WIKI_QUERY:slug|summary>> token. Agent decides
149→ *  when a reply warrants a wiki queries/ page and emits this token. */
150→export interface WikiQueryEntry {
151→  slug: string;
152→  summary: string;
153→}
154→
155→/** Payload of <<SPECIALIST_PROXY:name|message>>. Agent decides to hand off
156→ *  the user's message to a specialist in transparent proxy mode. */
157→export interface SpecialistProxyEntry {
158→  name: string;
159→  message: string;
160→}
161→
162→/** Payload of <<MOA_PLAN:{json}>> — raw single-line JSON emitted by the
163→ *  aggregator in MoA plan mode (SPEC-moa-provider Phase 2). Parsing and
164→ *  validation live in moa-plan.ts; this module only captures the span. */
165→export interface MoaPlanEntry {
166→  raw: string;
167→}
168→
169→export interface TransformedReply {
170→  /** Display text with all valid tokens stripped and excess blank lines collapsed. */
171→  text: string;
172→  /** Absolute paths requested via <<SEND_FILE>>. */
173→  sendFiles: string[];
174→  /** Schedules requested via <<SCHEDULE>> (only well-formed, first SCHEDULE_MAX_PER_MSG). */
175→  scheduleTokens: ScheduleTokenEntry[];
176→  /** ASK keyboards to render (de-duped by question_id). */
177→  askTokens: AskEntry[];
178→  /** De-duped skill usage reports (first SKILL_USED_MAX_PER_MSG distinct names). */
179→  skillUsages: SkillUsageEntry[];
180→  /** First GOAL_DONE token; `null` if none present. */
181→  goalDone: GoalDoneEntry | null;
