   214→const CODE_PLACEHOLDER_RE = /\u0000CODE(\d+)\u0000/g;
   215→
   216→function maskCodeRegions(text: string): {
   217→  masked: string;
   218→  restore: (s: string) => string;
   219→} {
   220→  const slots: string[] = [];
   221→  const masked = text.replace(/```[\s\S]*?```|`[^`\n]*`/g, (m) => {
   222→    const idx = slots.length;
