   239→  };
   240→  const parts = inner.split("|").map((s) => s.trim());
   241→  if (parts.length < 2) return reject("need at least question_id + 1 option");
   242→  const questionId = parts[0];
   243→  if (!ASK_ID_RE.test(questionId)) {
   244→    return reject(
   245→      `question_id "${questionId}" invalid (need [a-zA-Z0-9_-]{1,32}, got length ${questionId.length})`,
   246→    );
   247→  }
   248→  const options: AskOption[] = [];
   249→  const keys = new Set<string>();
   250→  let recommendedCount = 0;
   251→  for (const raw of parts.slice(1)) {
   252→    if (!raw) continue;
   253→    let spec = raw;
   254→    let recommended = false;
   255→    if (spec.startsWith("*")) {
   256→      recommended = true;
   257→      spec = spec.slice(1);
   258→    }
   259→    const eq = spec.indexOf("=");
   260→    if (eq <= 0) return reject(`option "${raw}" missing "key=label"`);
   261→    const key = spec.slice(0, eq).trim();
   262→    const label = spec.slice(eq + 1).trim();
   263→    if (!ASK_KEY_RE.test(key)) {
   264→      return reject(
   265→        `key "${key}" invalid (need [a-zA-Z0-9_-]{1,20}, got length ${key.length})`,
   266→      );
   267→    }
   268→    if (!label) return reject(`key "${key}" has empty label`);
   269→    if (label.length > ASK_LABEL_SOFT && label.length <= ASK_LABEL_MAX) {
   270→      // Soft-cap warning only; see ASK_LABEL_SOFT definition above for rationale.
   271→      console.warn(
   272→        `[ASK] label soft cap exceeded (got ${label.length}, soft ${ASK_LABEL_SOFT}): key="${key}" label="${label}"`,
   273→      );
   274→    }
   275→    if (label.length > ASK_LABEL_MAX) {
   276→      return reject(
   277→        `key "${key}" label too long (got ${label.length}, max ${ASK_LABEL_MAX}): "${label}"`,
   278→      );
   279→    }
   280→    if (keys.has(key)) return reject(`duplicate key "${key}"`);
   281→    keys.add(key);
   282→    if (recommended && recommendedCount > 0) recommended = false;
   283→    if (recommended) recommendedCount++;
   284→    options.push({ key, label, recommended });
   285→  }
   286→  if (options.length < 1) return reject("no valid options");
   287→  if (options.length > 8) return reject(`too many options (got ${options.length}, max 8)`);
   288→  return { questionId, options };
   289→}
   290→
   291→// ───────────────────────────────────────────────────────────────────────
   292→// Balanced scanner for tokens with free-form reason bodies (GOAL_DONE /
   293→// SKILL_USED / RESTART). Regex alone can't handle an agent that quotes
   294→// another token inside a reason (e.g. `<<GOAL_DONE:describes <<RESTART:
   295→// foo>> here>>`) because non-greedy `+?` collapses on the inner `>>`
   296→// and greedy `+` overshoots past the real closer. The scanner walks the
   297→// string tracking `<<` / `>>` depth so outer tokens consume any nested
   298→// literals before the narrower per-token regexes have a chance to see
   299→// them.
   300→//
   301→// Design notes:
   302→//   • Tokens are required to stay on a single line (spec §1.1/1.2/1.3).
   303→//     A `\n` inside a candidate span aborts the match and the opener
   304→//     stays visible.
   305→//   • Sentinel `\u0000CODE<n>\u0000` from code-region masking does not
   306→//     contain `<<` or `>>`, so scanner is safe to run on masked text.
   307→//   • Scanner is O(n) per call (single forward pass with a counter).
   308→//   • `runBalancedPhase` handles all three balanced-body prefixes in
   309→//     one pass so an outer `<<RESTART:...>>` containing an inner
   310→//     `<<GOAL_DONE:...>>` literal is consumed atomically without the
   311→//     inner token being extracted as a real GOAL_DONE.
   312→// ───────────────────────────────────────────────────────────────────────
   313→/** Run balanced-scanner phase for multiple token prefixes in a single
   314→ *  forward pass over `text`. At each `<<PREFIX:` encountered (first
   315→ *  match against any registered prefix wins — they don't overlap because
   316→ *  all prefixes are `<<UPPERCASE:`), we find the matching top-level
   317→ *  `>>` and hand the inner substring to that prefix's handler.
   318→ *
   319→ *  This outer-first strategy is what prevents a nested `<<GOAL_DONE:>>`
   320→ *  inside a `<<RESTART:...>>` reason from being extracted as a real
   321→ *  GOAL_DONE: the scanner sees the `<<RESTART:` opener first, walks to
   322→ *  its balanced closer (tracking depth so inner `<<>>` pairs don't
   323→ *  prematurely close), and consumes the whole span atomically.
   324→ *
   325→ *  Handler semantics (same as `replaceBalancedTokens`):
   326→ *    • returns string → replaces the full `<<PREFIX:...>>` span
   327→ *    • returns null  → token left verbatim, scanner continues past it
   328→ *
   329→ *  Newlines abort a candidate span (tokens are single-line per spec);
   330→ *  the scanner falls past the opener and keeps searching.
   331→ */
   332→function runBalancedPhase(
   333→  text: string,
   334→  handlers: Record<string, (inner: string) => string | null>,
   335→): string {
   336→  const prefixes = Object.keys(handlers);
   337→  let out = "";
   338→  let cursor = 0;
   339→  while (cursor < text.length) {
   340→    // Find the earliest occurrence of ANY registered prefix at or after cursor.
   341→    let bestStart = -1;
   342→    let bestPrefix = "";
   343→    for (const p of prefixes) {
   344→      const idx = text.indexOf(p, cursor);
   345→      if (idx >= 0 && (bestStart < 0 || idx < bestStart)) {
   346→        bestStart = idx;
   347→        bestPrefix = p;
   348→      }
   349→    }
   350→    if (bestStart < 0) {
   351→      out += text.slice(cursor);
   352→      break;
   353→    }
   354→    // Walk for balanced closer starting after the opener.
   355→    const innerStart = bestStart + bestPrefix.length;
   356→    let depth = 1;
   357→    let i = innerStart;
   358→    let aborted = false;
   359→    let closedAt = -1;
   360→    while (i < text.length - 1) {
   361→      const c = text.charCodeAt(i);
   362→      if (c === 0x0a || c === 0x0d) {
   363→        aborted = true;
   364→        break;
   365→      }
   366→      if (c === 0x3c && text.charCodeAt(i + 1) === 0x3c) {
   367→        depth++;
   368→        i += 2;
   369→        continue;
   370→      }
   371→      if (c === 0x3e && text.charCodeAt(i + 1) === 0x3e) {
   372→        depth--;
   373→        if (depth === 0) {
   374→          closedAt = i;
   375→          break;
   376→        }
   377→        i += 2;
   378→        continue;
   379→      }
   380→      i++;
   381→    }
   382→    if (aborted || closedAt < 0) {
   383→      // No valid balanced span for this opener. Skip past the opener
   384→      // itself (not past the whole line) so a later prefix can still
   385→      // match after it.
   386→      out += text.slice(cursor, bestStart + bestPrefix.length);
   387→      cursor = bestStart + bestPrefix.length;
   388→      continue;
   389→    }
   390→    const inner = text.slice(innerStart, closedAt);
   391→    const end = closedAt + 2;
   392→    const replacement = handlers[bestPrefix](inner);
   393→    out += text.slice(cursor, bestStart);
   394→    if (replacement === null) {
   395→      out += text.slice(bestStart, end);
   396→    } else {
   397→      out += replacement;
   398→    }
   399→    cursor = end;
   400→  }
   401→  return out;
   402→}
   403→
   404→
   405→/**
   406→ * Extract every token class from `rawReply` in one pass. Tokens inside
   407→ * code regions are ignored. Malformed tokens are left in the visible
   408→ * text as documentation for the agent. All limits come from
   409→ * docs/ab-token-protocol.md.
   410→ *
   411→ * Dependency injection: SCHEDULE time-parsers are passed via `parsers`
   412→ * so this module doesn't drag in schedule-store / recurrence graphs.
   413→ * Pass `null` (or just omit SCHEDULE parsing entirely) if the caller
   414→ * doesn't care about schedules — SCHEDULE tokens then stay in the text.
   415→ */
   416→export function transform(
   417→  rawReply: string,
   418→  parsers: ScheduleParsers | null = null,
   419→): TransformedReply {
   420→  if (!rawReply) {
   421→    return {
   422→      text: "",
   423→      sendFiles: [],
   424→      scheduleTokens: [],
   425→      askTokens: [],
   426→      skillUsages: [],
   427→      goalDone: null,
   428→      restartToken: null,
   429→      stickerEmotions: [],
   430→      skillPropose: null,
   431→      wikiQuery: null,
   432→      continueToken: false,
   433→      specialistProxy: null,
   434→      moaPlan: null,
   435→    };
   436→  }
   437→
   438→  const { masked, restore } = maskCodeRegions(rawReply);
   439→
   440→  // Collect payloads in a mutable object while we do the .replace passes.
   441→  const sendFiles: string[] = [];
   442→  const scheduleTokens: ScheduleTokenEntry[] = [];
   443→  const askTokens: AskEntry[] = [];
   444→  const skillUsages: SkillUsageEntry[] = [];
   445→  const seenSkillNames = new Set<string>();
   446→  const seenAskIds = new Set<string>();
   447→  let goalDone: GoalDoneEntry | null = null;
   448→  let restartToken: RestartTokenEntry | null = null;
   449→  let skillPropose: SkillProposeEntry | null = null;
   450→  let wikiQuery: WikiQueryEntry | null = null;
   451→  let specialistProxy: SpecialistProxyEntry | null = null;
   452→  let moaPlan: MoaPlanEntry | null = null;
   453→
   454→  // ────────────────────────────────────────────────────────────────
   455→  // Phase 1 — balanced-scanner tokens (free-form reason bodies).
   456→  // These run FIRST so that when an agent nests another token inside
   457→  // a reason (e.g. `<<GOAL_DONE:... <<RESTART:foo>> ...>>`), the outer
   458→  // match consumes the whole span including the nested literal. Later
   459→  // phases never see the inner token and can't trigger it by accident.
   460→  //
   461→  // Single forward pass over `masked`: at each `<<PREFIX:` (for any of
   462→  // the three balanced-body token classes), we walk to the matching
   463→  // top-level `>>` and hand the inner text to the right handler.
   464→  // Crucially, the walk happens before any narrower extractor runs —
   465→  // nested `<<...>>` inside a reason is consumed as part of the outer
   466→  // span and never appears as an independent token.
   467→  // ────────────────────────────────────────────────────────────────
   468→
   469→  let stripped = runBalancedPhase(masked, {
   470→    "<<SKILL_USED:": (inner) => {
   471→      if (skillUsages.length >= SKILL_USED_MAX_PER_MSG) return null;
   472→      const pipe = inner.indexOf("|");
   473→      if (pipe < 0) return null;
   474→      const name = inner.slice(0, pipe).trim();
   475→      let reason = inner.slice(pipe + 1).trim();
   476→      if (!/^[a-zA-Z0-9_-]{1,60}$/.test(name)) return null;
   477→      // 2026-05-03: truncate over-length reasons instead of rejecting.
   478→      // See BALANCED_REASON_MAX comment for rationale.
   479→      if (reason.length > BALANCED_REASON_MAX) reason = reason.slice(0, BALANCED_REASON_MAX);
   480→      if (seenSkillNames.has(name)) return ""; // dedup, first reason wins
   481→      seenSkillNames.add(name);
   482→      skillUsages.push({ name, reason });
   483→      return "";
   484→    },
   485→    "<<GOAL_DONE:": (inner) => {
   486→      if (goalDone !== null) return null;
   487→      let reason = inner.trim();
   488→      if (reason.length < 1) return null;
   489→      if (reason.includes("|")) return null;
   490→      // 2026-05-03: truncate over-length reasons instead of rejecting.
   491→      // Live bug: agent summaries for 10+ turn goals routinely exceeded
   492→      // the old 200-char cap and the token was left verbatim, causing
   493→      // goalDone=null and an infinite continuation loop.
   494→      if (reason.length > BALANCED_REASON_MAX) reason = reason.slice(0, BALANCED_REASON_MAX);
   495→      goalDone = { reason };
   496→      return "";
   497→    },
   498→    "<<RESTART:": (inner) => {
   499→      if (restartToken !== null) return null;
   500→      let reason = inner.trim();
   501→      if (reason.includes("|")) return null;
   502→      // 2026-05-03: truncate over-length reasons instead of rejecting.
   503→      if (reason.length > BALANCED_REASON_MAX) reason = reason.slice(0, BALANCED_REASON_MAX);
   504→      // Empty reason → use default so markRestart doesn't reject.
   505→      if (!reason) reason = RESTART_BARE_REASON;
   506→      restartToken = { reason };
   507→      return "";
   508→    },
   509→    "<<SKILL_PROPOSE:": (inner) => {
   510→      if (skillPropose !== null) return null; // only first one
   511→      const pipe = inner.indexOf("|");
   512→      if (pipe < 0) return null;
   513→      const name = inner.slice(0, pipe).trim();
   514→      const reason = inner.slice(pipe + 1).trim();
   515→      if (!/^[a-z0-9_-]{1,60}$/.test(name)) return null;
   516→      if (!reason || reason.length > 500) return null;
   517→      skillPropose = { name, reason };
   518→      return "";
   519→    },
   520→    "<<WIKI_QUERY:": (inner) => {
   521→      if (wikiQuery !== null) return null; // only first one
   522→      const pipe = inner.indexOf("|");
   523→      if (pipe < 0) return null;
   524→      const slug = inner.slice(0, pipe).trim();
   525→      const summary = inner.slice(pipe + 1).trim();
   526→      if (!/^[a-z0-9_-]{1,80}$/.test(slug)) return null;
   527→      if (!summary || summary.length > 200) return null;
   528→      wikiQuery = { slug, summary };
   529→      return "";
   530→    },
   531→    "<<SPECIALIST_PROXY:": (inner) => {
   532→      if (specialistProxy !== null) return null; // only first one
   533→      const pipe = inner.indexOf("|");
   534→      if (pipe < 0) return null;
   535→      const name = inner.slice(0, pipe).trim();
   536→      const message = inner.slice(pipe + 1).trim();
   537→      if (!/^[a-zA-Z0-9_-]{1,60}$/.test(name)) return null;
   538→      if (!message) return null;
   539→      specialistProxy = { name, message };
   540→      return "";
   541→    },
   542→    "<<MOA_PLAN:": (inner) => {
   543→      if (moaPlan !== null) return null; // only first one
   544→      const raw = inner.trim();
   545→      // Must at least look like a JSON object — anything else stays
   546→      // visible so the aggregator sees its own malformed emission.
   547→      // Balanced-scanner constraints (single line, no bare `>>` inside)
   548→      // are part of the token contract in the plan-mode prompt.
   549→      if (!raw.startsWith("{") || !raw.endsWith("}")) return null;
   550→      moaPlan = { raw };
   551→      return "";
   552→    },
   553→  });
   554→
   555→  // ────────────────────────────────────────────────────────────────
   556→  // Phase 2 — regex-based tokens (structured bodies: path / time-spec
   557→  // / id|k=v). These don't nest other tokens so plain regex is fine.
   558→  // ────────────────────────────────────────────────────────────────
   559→
   560→  // Pre-fix: repair SEND_FILE paths broken by JSON deserialization.
   561→  // When the agent emits backslash Windows paths (F:\AI\...), JSON
   562→  // serialization in the CLI turns \r → CR, \n → LF, \t → TAB, etc.
   563→  // This makes the regex (which stops at \r\n) unable to capture the
   564→  // full path. Fix: within <<SEND_FILE:...>> spans, replace control
   565→  // chars back to their backslash-letter originals.
   566→  const SEND_FILE_REPAIR_RE = /<<SEND_FILE:\s*([\s\S]+?)\s*>>/g;
   567→  stripped = stripped.replace(SEND_FILE_REPAIR_RE, (_m, body: string) => {
   568→    const repaired = body
   569→      .replace(/\r/g, "\\r")
   570→      .replace(/\n/g, "\\n")
   571→      .replace(/\t/g, "\\t");
   572→    return `<<SEND_FILE:${repaired}>>`;
   573→  });
   574→
   575→  // SEND_FILE
   576→  stripped = stripped.replace(SEND_FILE_RE, (_m, p: string) => {
   577→    sendFiles.push(p.trim());
   578→    return "";
   579→  });
   580→
   581→  // STICKER
   582→  const stickerEmotions: string[] = [];
   583→  stripped = stripped.replace(STICKER_RE, (_m, emotion: string) => {
   584→    const key = emotion.trim().toLowerCase();
   585→    if (STICKER_MAP[key] && !stickerEmotions.includes(key)) {
   586→      stickerEmotions.push(key);
   587→    }
   588→    return "";
   589→  });
   590→
   591→  // SCHEDULE (only if parsers provided)
   592→  if (parsers) {
   593→    const now = parsers.now ? parsers.now() : Date.now();
   594→    stripped = stripped.replace(SCHEDULE_RE, (match, inner: string) => {
   595→      if (scheduleTokens.length >= SCHEDULE_MAX_PER_MSG) return match;
   596→      const pipe = inner.indexOf("|");
   597→      if (pipe <= 0) return match;
   598→      const timeRaw = inner.slice(0, pipe).trim();
   599→      let prompt = inner.slice(pipe + 1).trim();
   600→      if (!prompt) return match;
   601→      if (prompt.length > SCHEDULE_PROMPT_MAX) {
   602→        prompt = prompt.slice(0, SCHEDULE_PROMPT_MAX);
   603→      }
   604→      const recurrence = parsers.parseRecurrence(timeRaw);
   605→      if (recurrence) {
   606→        const firstRunAt = parsers.computeNextRunAt(recurrence, now - 1);
   607→        if (firstRunAt === null) return match;
   608→        scheduleTokens.push({
   609→          runAt: firstRunAt,
   610→          prompt,
   611→          whenLabel: timeRaw,
   612→          recurrence,
   613→        });
   614→        return "";
   615→      }
   616→      let runAt: number | null = null;
   617→      const dur = parsers.parseDuration(timeRaw);
   618→      if (dur !== null) {
   619→        runAt = now + dur;
   620→      } else {
   621→        const dt = parsers.parseAbsoluteTime(timeRaw);
   622→        if (dt && dt.getTime() > now) runAt = dt.getTime();
   623→      }
   624→      if (runAt === null) return match;
   625→      scheduleTokens.push({ runAt, prompt, whenLabel: timeRaw });
   626→      return "";
   627→    });
   628→  }
   629→
   630→  // ASK
   631→  stripped = stripped.replace(ASK_RE, (match, inner: string) => {
   632→    const entry = parseAskInner(inner);
   633→    if (!entry) return match;
   634→    if (seenAskIds.has(entry.questionId)) {
   635→      const idx = askTokens.findIndex((a) => a.questionId === entry.questionId);
   636→      if (idx >= 0) askTokens.splice(idx, 1);
   637→    }
   638→    seenAskIds.add(entry.questionId);
   639→    askTokens.push(entry);
   640→    return "";
   641→  });
   642→
   643→  // Bare RESTART. Keep this after the balanced phase so `<<RESTART:...>>`
   644→  // retains nested-token handling, while the short host-side form also works.
   645→  stripped = stripped.replace(RESTART_BARE_RE, (match) => {
   646→    if (restartToken !== null) return match;
   647→    restartToken = { reason: RESTART_BARE_REASON };
   648→    return "";
   649→  });
   650→
   651→  // CONTINUE — bare token, no payload. Agent signals "I have more work
   652→  // to do, please give me another turn" without requiring an active /goal.
   653→  let continueToken = false;
   654→  stripped = stripped.replace(CONTINUE_RE, () => {
   655→    continueToken = true;
   656→    return "";
   657→  });
   658→
   659→  // Hide trailing unterminated token opener (see helper docs below).
   660→  // 2026-05-02: originally this ran only in renderReply() for streaming
   661→  // frames, under the assumption final render always receives a fully-
   662→  // closed token set. Live testing showed that's wrong — when the agent
   663→  // ends its stream mid-token (e.g. abrupt end-of-turn right after
   664→  // `<<GOAL_DONE:reason`), the final render's ab7.text still carries
   665→  // the raw opener and the user sees `<<GOAL_DONE:...` glued onto the
   666→  // message tail. Running hide on transform()'s cleaned output makes
   667→  // both paths (streaming + final) share the same UX guarantee.
   668→  const hidden = hideTrailingUnterminatedToken(
   669→    restore(stripped).replace(/\n{3,}/g, "\n\n").trim(),
   670→  );
   671→
   672→  return {
   673→    text: hidden,
   674→    sendFiles,
   675→    scheduleTokens,
   676→    askTokens,
   677→    skillUsages,
   678→    goalDone,
   679→    restartToken,
   680→    stickerEmotions,
   681→    skillPropose,
   682→    wikiQuery,
   683→    continueToken,
   684→    specialistProxy,
   685→    moaPlan,
   686→  };
   687→}
   688→
   689→// ───────────────────────────────────────────────────────────────────────
   690→// Streaming UX helper: hide a trailing unterminated token opener.
   691→// ───────────────────────────────────────────────────────────────────────
   692→// When the agent is mid-write on a token like `<<GOAL_DONE:reason still
   693→// being typed…`, transform() can't match the token (no closing `>>`)
   694→// and leaves the opener visible in the output text. The user then sees
   695→// `<<GOAL_DONE:reason still…` flicker in the placeholder until the
   696→// agent emits `>>` — or worse, sees it frozen if the stream ends
   697→// mid-token (final render also inherits the raw opener).
   698→//
   699→// This helper finds the LAST known-prefix opener in `text` that has no
   700→// matching `>>` after it, and replaces the span from that opener to EOF
   701→// with `…`. Only unterminated openers are trimmed; fully-terminated
   702→// tokens (malformed or not) are left alone because they've already been
   703→// decided by transform()'s extractors or kept as literal text.
   704→//
   705→// Called from transform()'s tail so both streaming frames and the final
   706→// render get the same treatment. Exported for unit testing.
   707→export function hideTrailingUnterminatedToken(text: string): string {
   708→  const openerRe = /<<(?:GOAL_DONE|SKILL_USED|SKILL_PROPOSE|ASK|SCHEDULE|SEND_FILE|STICKER|WIKI_QUERY):|<<RESTART(?::|>?$)/g;
   709→  let lastOpener = -1;
   710→  for (;;) {
   711→    const m = openerRe.exec(text);
   712→    if (!m) break;
   713→    lastOpener = m.index;
   714→  }
   715→  if (lastOpener < 0) return text;
   716→  const tail = text.slice(lastOpener);
   717→  if (tail.includes(">>")) return text; // fully-terminated — leave it
   718→  return text.slice(0, lastOpener).replace(/\s+$/, "") + "\n…";
   719→}
   720→
   721→// ───────────────────────────────────────────────────────────────────────
   722→// Thin per-token helpers — kept for callers that don't want the full
   723→// `transform()` (e.g. replyWithAsk in index.ts only needs ASK parsing).
   724→// These are all backed by `transform()` so behavior stays uniform.
   725→// ───────────────────────────────────────────────────────────────────────
   726→
   727→export function extractSendFileTokens(text: string): {
   728→  text: string;
   729→  paths: string[];
   730→} {
   731→  const r = transform(text, null);
   732→  return { text: r.text, paths: r.sendFiles };
   733→}
   734→
   735→export function extractAskTokens(text: string): {
   736→  text: string;
   737→  asks: AskEntry[];
   738→} {
   739→  const r = transform(text, null);
   740→  return { text: r.text, asks: r.askTokens };
   741→}
   742→
   743→export function extractScheduleTokens(
   744→  text: string,
   745→  parsers: ScheduleParsers,
   746→): { text: string; entries: ScheduleTokenEntry[] } {
   747→  const r = transform(text, parsers);
