/**
 * Bot creation, rate-limit observer, command specs, and keyboard builders.
 * Extracted from index.ts (P6 split).
 */
import { Bot, InlineKeyboard, Keyboard } from "grammy";
import { autoRetry } from "@grammyjs/auto-retry";
import { config } from "./config.js";

// ─── Command Specs ────────────────────────────────────────────────────────────

export interface CommandSpec {
  name: string;
  button: string;
  usage: string;
  desc: string;
  takesArg?: boolean;
}

export const COMMAND_SPECS: readonly CommandSpec[] = [
  { name: "whoami",   button: "👤 whoami",   usage: "/whoami",             desc: "顯示你的 Telegram user id 與 chat id。" },
  { name: "reset",    button: "🔄 reset",    usage: "/reset [clean]",       desc: "結束目前 session。加 clean 則下次對話不帶入上次上下文。" },
  { name: "cancel",   button: "✋ cancel",   usage: "/cancel",             desc: "取消目前正在執行的回合。" },
  { name: "restart",  button: "♻️ restart",  usage: "/restart",            desc: "重新啟動 bridge 程序（先擷取事實再重啟）。" },
  { name: "save",     button: "💾 save",     usage: "/save",               desc: "將目前對話匯出到 AIMemory/sessions/。" },
  { name: "handoff",  button: "📦 handoff",  usage: "/handoff [keep] [backup]", desc: "收工交接：產生 handoff 摘要、寫入長期記憶候選；預設會結束目前 session，keep 可保留，backup 可接著跑備份。" },
  { name: "sendfile", button: "📎 sendfile", usage: "/sendfile <path>",    desc: "從允許的根目錄下把檔案傳回此聊天室。", takesArg: true },
  { name: "context",  button: "📋 context",  usage: "/context",            desc: "顯示目前 session 的 context 摘要。" },
  { name: "usage",    button: "📊 usage",    usage: "/usage",              desc: "顯示 context / token 使用量。" },
  { name: "remember", button: "📝 remember", usage: "/remember [fact]",    desc: "新增一則事實；不帶參數則從目前 session 擷取事實（按鈕採此行為）。" },
  { name: "memory",   button: "🧠 memory",   usage: "/memory",             desc: "顯示你的長期記憶檔內容。" },
  { name: "summary",  button: "📚 summary",  usage: "/summary",            desc: "整併長期記憶（合併重複、保留重點）。" },
  { name: "memorytoskill", button: "🧩 mem→skill", usage: "/MemoryToSkill", desc: "執行 memory-to-skill：掃 sessions/ 抽取可重用模式，寫成 ~/.kiro/skills/ms-*/ SKILL.md。" },
  { name: "backup",   button: "☁️ backup",   usage: "/backup",             desc: "把 AIMemory 與 agent 設定目錄（~/.kiro 或 ~/.codex 或 ~/.claude）下的 agents/settings/steering/powers/skills 備份到 GitHub Private repo（robocopy /MIR + git commit + push）。" },
  { name: "topicreview", button: "🏷️ topic-review", usage: "/topic-review", desc: "讓 agent 重新 review 長期記憶的 topic 分類、直接改寫 topics.json 並 rebuild 所有 shard（全自動，不需確認；舊檔會備份到 topics.bak.<ts>.json）。" },
  { name: "refreshrouting", button: "📚 refresh-routing", usage: "/refresh-routing", desc: "讓 agent 重新掃 NotebookLM 所有 notebook、抽關鍵字、更新 MEMORY_DIR/config/notebooklm-routing.json（舊檔會備份到 notebooklm-routing.bak.<ts>.json）。新增 notebook 後執行這個刷新 RAG 路由表。" },
  { name: "schedule", button: "⏰ schedule", usage: "/schedule <add|at|every|daily|weekly|cron|list|remove|run> …", desc: "排程 prompt。一次性：/schedule add 30m 提醒；/schedule at 09:00 早安。常態性：/schedule every 30m 喝水；/schedule daily 09:00 早安；/schedule weekly mon 09:00 週會；/schedule cron '*/5 * * * *' ping。", takesArg: true },
  { name: "intel", button: "📰 intel", usage: "/intel <profiles|show|profile|sources|source|run|status|retry|retry-source|search|clusters|cluster|weekly|podcast|schedule> …", desc: "管理 Daily Intel 情報 Profile、來源、執行、Podcast、搜尋、週報趨勢、聚類 review、精準重試及排程。", takesArg: true },
  { name: "skillusage", button: "📚 skillusage", usage: "/skillusage", desc: "列出所有 skill 的使用狀態：pinned / 最近新增 / bridge 端從未看到 agent 用過 / orphan。使用紀錄存在 ${MEMORY_DIR}/config/skill-usage.json（跨 CLI 共用）。" },
  { name: "pin", button: "📌 pin", usage: "/pin <skill-name>", desc: "在 skill-usage.json 把 skill 標為 pinned，避免未來 agent auto-edit/archive（目前純標記，實際 enforcement 要等 agent 有改 skill 能力）。", takesArg: true },
  { name: "unpin", button: "📍 unpin", usage: "/unpin <skill-name>", desc: "取消 pin 標記。", takesArg: true },
  { name: "goal", button: "🎯 goal", usage: "/goal [N] <objective> | /goal <status|pause|resume|clear>", desc: "設持續性目標。第一個 token 是 1–50 的整數可當 per-goal turn budget（超範圍就忽略，fallback 到 GOAL_DEFAULT_MAX_TURNS）。agent 回覆不帶 <<GOAL_DONE:reason>> 就會自動塞 continuation turn；達到 turn budget 自動暫停（/goal resume 重跑，/goal clear 放棄）。", takesArg: true },
  { name: "moa", button: "🧠 moa", usage: "/moa [preset] <問題>", desc: "Mixture of Agents 盲審：多個 reference 模型獨立回答同一問題，主 agent 綜合。不指定 preset 時依語意自動路由（red-team / fact-check / default）。", takesArg: true },
  { name: "status", button: "📊 status", usage: "/status", desc: "顯示進行中的 specialist/relay 任務狀態。有任務時提供 Mini App 監控面板按鈕。" },
  { name: "relay", button: "🔁 relay", usage: "/relay <status|reopen>", desc: "顯示 relay transport 狀態，或解除 relay maxTurns 封鎖。", takesArg: true },
  { name: "model", button: "🧠 model", usage: "/model [name]", desc: "切換 LLM 模型。不帶參數顯示當前模型與可用列表；帶參數切換（kiro/claude/gpt4o/gemini/deepseek/groq/local）。切換會重置對話。切 ACP CLI agent 請用 /agent。", takesArg: true },
  { name: "agent", button: "🤝 agent", usage: "/agent [name]", desc: "切換 ACP CLI agent（Kiro/Claude Code/Codex subprocess），自動交接對話摘要不掉記憶。不帶參數顯示當前 agent 與可用列表。backend 定義在 ${MEMORY_DIR}/config/acp-providers.json。", takesArg: true },
  { name: "session", button: "🗂 session", usage: "/session [new|rename|close] [名稱]", desc: "多 session 管理：不帶參數列出所有對話（inline keyboard 點擊切換，走 ACP session/load 恢復完整 context）；new 開新對話（現行對話 park 保留）；rename 改名；close 關閉現行對話。需啟用 ACP_SESSION_RESUME。" },
  { name: "dream", button: "🌙 dream", usage: "/dream", desc: "夜間維運宏指令，依序跑多個 bridge 指令（預設 10 步：memorytoskill→topicreview→wikisync→factlint→wikilint→skilllint→specialistreview→artifactcleanup→backup→restart）。步驟可由 MEMORY_DIR/config/dream.json 自訂（schema：{ steps:[{cmd,label?}], continue_on_error? }；保留字 dream 會被防呆跳過）。適合單條 daily 排程取代多條。" },
  { name: "wikisync", button: "📖 wikisync", usage: "/wikisync", desc: "從 topic shards（≥5 facts）產生/更新 wiki concepts 頁面。" },
  { name: "factlint", button: "🧹 factlint", usage: "/factlint", desc: "掃描 topic shards 找矛盾/過時/重複/瑣碎 facts 並清理。" },
  { name: "skilllint", button: "🔧 skilllint", usage: "/skilllint", desc: "掃描 skills 找過時/低使用率/衝突/孤兒，產出健康報告與建議動作。" },
  { name: "wikilint", button: "📋 wikilint", usage: "/wikilint", desc: "掃描 wiki pages 找過時/孤兒/斷連 wikilink，產出健康報告。" },
  { name: "menu",     button: "⌨️ menu",     usage: "/menu",               desc: "顯示常駐的指令鍵盤。" },
  { name: "hide",     button: "🙈 hide",     usage: "/hide",               desc: "收起常駐的指令鍵盤。" },
  { name: "back",     button: "↩️ back",     usage: "/back",               desc: "退出 specialist proxy 模式，切回主 agent。" },
  { name: "specialist", button: "🤖 specialist", usage: "/specialist create <name>", desc: "自動分析 skill-usage.json + topics 產生 specialist 配置（agents/{name}.json + specialists.json）。", takesArg: true },
  { name: "specialistreview", button: "🔍 specialist-review", usage: "/specialistreview", desc: "掃描 topic shards 找出足夠大的 cluster 提議新 specialist。" },
  { name: "artifactcleanup", button: "🧹 artifact-cleanup", usage: "/artifactcleanup", desc: "清理超過 7 天的 specialist artifact 檔案。" },
  { name: "dailylog", button: "📓 daily-log", usage: "/dailylog", desc: "產出今天的 daily log 摘要（掃當天 sessions）。" },
  { name: "sharedsync", button: "🔁 shared-sync", usage: "/sharedsync [message]", desc: "同步 shared knowledge repo：commit 本機變更、rebase pull、push，push 被拒時重試一次。" },
  { name: "docupdate", button: "📄 docupdate", usage: "/docupdate", desc: "檢查 README 與 usage-guide.html 的差異，自動補上缺少的功能說明。" },
  { name: "skillsearch", button: "🛒 skillsearch", usage: "/skillsearch <keyword>", desc: "搜尋 SkillsMP marketplace 的公開 SKILL.md，支援查看詳情和一鍵安裝到正本目錄。", takesArg: true },
  { name: "help",     button: "❓ help",     usage: "/help",               desc: "顯示此說明選單。" },
] as const;

// ─── Keyboard builders ────────────────────────────────────────────────────────

export function buildHelpMenuKeyboard(): InlineKeyboard {
  const kb = new InlineKeyboard();
  COMMAND_SPECS.forEach((spec, i) => {
    kb.text(spec.button, `help:${spec.name}`);
    if ((i + 1) % 3 === 0) kb.row();
  });
  return kb;
}

export function buildCommandDetailKeyboard(spec: CommandSpec): InlineKeyboard {
  const kb = new InlineKeyboard();
  if (!spec.takesArg) {
    kb.text(`▶ 執行 ${spec.usage}`, `run:${spec.name}`).row();
  }
  kb.text("⬅️ 返回選單", "help:_back");
  return kb;
}

export async function registerBotCommands(bot: Bot): Promise<void> {
  const commands = COMMAND_SPECS.map((spec) => ({
    command: spec.name,
    description: `${spec.button} — ${spec.desc}`
      .replace(/[`*_]/g, "")
      .slice(0, 256),
  }));
  // 先清掉 all_private_chats scope 的殘留指令：該 scope 比 default 更具體、會
  // 遮蔽下面設定的完整選單（曾發生外部程式拿到 token 後寫入 3 個指令蓋掉選單）。
  // 對空 scope 呼叫也回 ok，冪等。若未來要刻意用此 scope 配私聊選單，需移除此行。
  await bot.api.deleteMyCommands({ scope: { type: "all_private_chats" } });
  await bot.api.setMyCommands(commands);
  await bot.api.setChatMenuButton({ menu_button: { type: "commands" } });
}

export function buildReplyKeyboard(): Keyboard {
  const rows: string[][] = [
    ["/help", "/context", "/usage"],
    ["/memory", "/summary", "/MemoryToSkill"],
    ["/wikisync", "/factlint", "/wikilint", "/skilllint", "/dream"],
    ["/sharedsync"],
    ["/save", "/handoff", "/reset", "/cancel"],
    ["/restart", "/hide"],
  ];
  const kb = new Keyboard();
  for (const row of rows) {
    for (const label of row) kb.text(label);
    kb.row();
  }
  return kb.resized().persistent();
}

function escHtml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

export const HELP_INTRO =
  "<b>指令選單</b> — 點選任一指令即可查看說明。\n" +
  "需要參數的指令（例如 <code>/sendfile &lt;path&gt;</code>）仍請直接輸入。";

export function renderCommandDetail(spec: CommandSpec): string {
  return `<b>${escHtml(spec.usage)}</b>\n${escHtml(spec.desc)}`;
}

// ─── Bot factory with rate-limit observer ─────────────────────────────────────

export type RecoveryListener = () => void | Promise<void>;

export interface BotSetupResult {
  bot: Bot;
  rateLimitedUntil: () => number;
  onRateLimitRecovery: (fn: RecoveryListener) => () => void;
  queuePendingMessage: (chatId: number, text: string) => void;
}

export function createBot(): BotSetupResult {
  const bot = new Bot(config.telegramToken);

  bot.api.config.use(
    autoRetry({
      maxRetryAttempts: 3,
      maxDelaySeconds: config.telegramAutoRetryMaxDelaySeconds,
    })
  );

  let rateLimitedUntil = 0;
  let lastRateLimitSecs = 0;
  let rateLimitChatId: number | undefined;
  let rateLimitRecoveryTimer: NodeJS.Timeout | null = null;
  const pendingMessages: Array<{ chatId: number; text: string }> = [];
  const rateLimitRecoveryListeners: Set<RecoveryListener> = new Set();

  async function flushPendingMessages() {
    const startCount = pendingMessages.length;
    let flushed = 0;
    while (pendingMessages.length > 0) {
      if (rateLimitedUntil > Date.now()) {
        console.warn(
          `[rate-limit] flush paused mid-way: flushed ${flushed}/${startCount}, ${pendingMessages.length} remain`,
        );
        return;
      }
      const { chatId, text } = pendingMessages.shift()!;
      try {
        await bot.api.sendMessage(chatId, text);
        flushed++;
        console.log(`[rate-limit] flushed queued message → chat ${chatId} (${flushed}/${startCount})`);
      } catch (err) {
        console.error("[rate-limit] replay failed, requeueing:", err);
        pendingMessages.unshift({ chatId, text });
        return;
      }
      await new Promise<void>((r) => setTimeout(r, 1100));
    }
    if (startCount > 0) {
      console.log(`[rate-limit] flush complete: ${flushed}/${startCount} delivered`);
    }
  }

  bot.api.config.use(async (prev, method, payload, signal) => {
    const res = await prev(method, payload, signal);
    const retryAfter = (res as any)?.parameters?.retry_after;
    if (typeof retryAfter === "number" && retryAfter > 0) {
      const until = Date.now() + retryAfter * 1000;
      const chatId = Number((payload as any)?.chat_id);
      if (Number.isFinite(chatId)) rateLimitChatId = chatId;
      if (until > rateLimitedUntil) {
        rateLimitedUntil = until;
        if (retryAfter > lastRateLimitSecs) lastRateLimitSecs = retryAfter;
        console.warn(
          `[rate-limit] Telegram 429: retry_after=${retryAfter}s chat=${
            Number.isFinite(chatId) ? chatId : "?"
          } method=${method} — pausing edits until ${new Date(until).toISOString()}`
        );
        if (rateLimitRecoveryTimer) {
          clearTimeout(rateLimitRecoveryTimer);
          rateLimitRecoveryTimer = null;
        }
        const waitMs = until - Date.now() + 500;
        rateLimitRecoveryTimer = setTimeout(async () => {
          rateLimitRecoveryTimer = null;
          const peak = lastRateLimitSecs;
          const target = rateLimitChatId;
          lastRateLimitSecs = 0;
          rateLimitedUntil = 0;
          console.log(
            `[rate-limit] recovered after ${peak}s — flushing ${pendingMessages.length} pending message(s)`
          );
          if (target === undefined) return;
          try {
            await bot.api.sendMessage(
              target,
              `⏳ Telegram 限流解除（等了 ${peak}s）— 現在可以正常收發訊息了。`
            );
          } catch (err) {
            console.error("[rate-limit] failed to send recovery notice:", err);
          }
          for (const fn of Array.from(rateLimitRecoveryListeners)) {
            try {
              await fn();
            } catch (err) {
              console.error("[rate-limit] recovery listener failed:", err);
            }
          }
          await flushPendingMessages();
        }, waitMs);
      }
    }
    return res;
  });

  return {
    bot,
    rateLimitedUntil: () => rateLimitedUntil,
    onRateLimitRecovery(fn: RecoveryListener) {
      rateLimitRecoveryListeners.add(fn);
      return () => rateLimitRecoveryListeners.delete(fn);
    },
    queuePendingMessage(chatId: number, text: string) {
      pendingMessages.push({ chatId, text });
    },
  };
}

