export interface TelegramRichMessageDraft {
  markdown: string;
}

export function renderTelegramRichDraft(text: string): TelegramRichMessageDraft {
  return { markdown: text.replace(/\r\n/g, "\n") };
}

export async function tryEditRichMessageDraft(
  api: unknown,
  chatId: number,
  messageId: number,
  text: string,
  extra: Record<string, unknown> = {},
): Promise<boolean> {
  // 注意：真 grammY 的 api.raw 是 Proxy，任何 method 名都回傳 callable，
  // 所以 typeof guard 只對 fake api（測試）或非 grammY adapter 有效；
  // 真正的「不支援」偵測靠下面的 catch（server 拒絕時回 false 讓呼叫端走 plain fallback）。
  const raw = (api as { raw?: { editMessageText?: unknown } }).raw;
  const method = raw?.editMessageText;
  if (typeof method !== "function") return false;
  const rich_message = renderTelegramRichDraft(text);
  try {
    await method.call(raw, {
      chat_id: chatId,
      message_id: messageId,
      ...extra,
      rich_message,
    });
    return true;
  } catch {
    // Rich edit 失敗（含 400 identical / server 不支援 rich_message）→
    // 回 false 讓呼叫端退回 plain editMessageText，不讓例外吃掉整幀。
    return false;
  }
}

/**
 * Send a new rich message (for multi-chunk continuation messages).
 * Rich sends go through the dedicated Bot API 10.1 `sendRichMessage` method —
 * `sendMessage` ignores a `rich_message` param and delivers plain text.
 * Returns the sent message object, or undefined if rich send is unsupported
 * or rejected (caller falls back to a plain send).
 */
export async function trySendRichMessage(
  api: unknown,
  chatId: number,
  text: string,
  extra: Record<string, unknown> = {},
): Promise<{ message_id: number } | undefined> {
  const raw = (api as { raw?: { sendRichMessage?: unknown } }).raw;
  const method = raw?.sendRichMessage;
  if (typeof method !== "function") return undefined;
  const rich_message = renderTelegramRichDraft(text);
  try {
    const result = await method.call(raw, {
      chat_id: chatId,
      ...extra,
      rich_message,
    });
    return result as { message_id: number } | undefined;
  } catch {
    return undefined;
  }
}

import { readFileSync } from "node:fs";
import ts from "typescript";

const source = readFileSync("src/telegram-rich-renderer.ts", "utf8");
const js = ts.transpileModule(source, {
  compilerOptions: {
    module: ts.ModuleKind.ES2022,
    target: ts.ScriptTarget.ES2022,
  },
}).outputText;

const mod = await import(`data:text/javascript;base64,${Buffer.from(js).toString("base64")}`);
const { renderTelegramRichDraft, tryEditRichMessageDraft, trySendRichMessage } = mod;

function assert(name, condition, detail = "") {
  if (!condition) {
    throw new Error(`${name}${detail ? `: ${detail}` : ""}`);
  }
  console.log(`ok - ${name}`);
}

const draft = renderTelegramRichDraft(`# Rich Messages Test

Plain paragraph for rich message smoke.
- List A
- List B
| Column A | Column B |
| --- | --- |
| 1 | 2 |

\`\`\`ts
const ok = true;
\`\`\`

:::unknown
Unsupported extension block should pass through unchanged.`);

assert("rich draft uses Bot API markdown input", typeof draft.markdown === "string");
assert("rich draft keeps heading markdown", draft.markdown.includes("# Rich Messages Test"));
assert("rich draft keeps unordered list markdown", draft.markdown.includes("- List A"));
assert("rich draft keeps table markdown", draft.markdown.includes("| Column A | Column B |"));
assert("rich draft keeps code fence markdown", draft.markdown.includes("```ts"));
assert("rich draft normalizes CRLF", !draft.markdown.includes("\r\n"));

const missingApi = await tryEditRichMessageDraft({}, 1, 2, "hello");
assert("missing rich API returns false for fallback", missingApi === false);

let captured = null;
const fakeApi = {
  raw: {
    async editMessageText(payload) {
      captured = payload;
    },
  },
};
const richApi = await tryEditRichMessageDraft(fakeApi, 11, 22, "# Hi");
assert("available rich API returns true", richApi === true);
assert("rich API receives chat id", captured?.chat_id === 11);
assert("rich API receives message id", captured?.message_id === 22);
assert("rich API receives Bot API rich_message markdown", captured?.rich_message?.markdown === "# Hi");
assert("rich API does not send legacy text", captured?.text === undefined);

captured = null;
await tryEditRichMessageDraft(fakeApi, 33, 44, "# Hi", {
  reply_markup: { inline_keyboard: [[{ text: "OK", callback_data: "ok" }]] },
});
assert("rich API preserves extra reply markup", captured?.reply_markup?.inline_keyboard?.[0]?.[0]?.text === "OK");

// ─── trySendRichMessage ───────────────────────────────────────────────────

const missingSendApi = await trySendRichMessage({ raw: {} }, 1, "hello");
assert("missing sendRichMessage returns undefined for fallback", missingSendApi === undefined);

let sendCaptured = null;
const fakeSendApi = {
  raw: {
    async sendRichMessage(payload) {
      sendCaptured = payload;
      return { message_id: 99 };
    },
  },
};
const sent = await trySendRichMessage(fakeSendApi, 55, "# Chunk 2", {
  reply_markup: { inline_keyboard: [[{ text: "OK", callback_data: "ok" }]] },
});
assert("rich send returns sent message", sent?.message_id === 99);
assert("rich send uses sendRichMessage method with chat id", sendCaptured?.chat_id === 55);
assert("rich send passes rich_message markdown", sendCaptured?.rich_message?.markdown === "# Chunk 2");
assert("rich send does not pass legacy text param", sendCaptured?.text === undefined);
assert("rich send preserves reply markup", sendCaptured?.reply_markup?.inline_keyboard?.[0]?.[0]?.text === "OK");

const throwingSendApi = {
  raw: {
    async sendRichMessage() {
      throw new Error("rich send rejected");
    },
  },
};
const rejected = await trySendRichMessage(throwingSendApi, 55, "# Chunk 2");
assert("rich send failure returns undefined for plain fallback", rejected === undefined);

console.log("rich renderer smoke OK");

