// ---------------------------------------------------------------------------
// renderReply (streaming display)
// ---------------------------------------------------------------------------
export interface RenderResult {
  content: string;
  parseMode: "HTML" | undefined;
}

export function renderReply(
  session: ChatSession,
  done: boolean,
  parsers: ScheduleParsers,
): RenderResult {
  const toolLines = toolPrefixLines(session);
  const tools = toolLines.length ? toolLines.join("\n") + "\n\n" : "";
  const cursor = done ? "" : " ▍";
  const emptyFallback = () => {
    if (!done) return session.thinkingBuffer ? "" : "Thinking…";
    const n = session.toolTimeline.length;
    return n > 0 ? `(no text yet — ${n} tool call${n === 1 ? "" : "s"} so far)` : "(no response)";
  };

  // Show thinking progress during streaming (hide when done)
  let thinkingBlock = "";
  if (!done && session.thinkingBuffer) {
    // Show last ~200 chars of thinking as blockquote
    const t = session.thinkingBuffer;
    const preview = t.length > 200 ? "…" + t.slice(-200) : t;
    thinkingBlock = "💭 " + preview.split("\n").join("\n> ") + "\n\n";
  }

  const raw = session.buffer || emptyFallback();
  const stripped = transformReplyTokens(raw, parsers).text;
  let body = stripped || emptyFallback();
  if (body.length > TG_MAX) {
    body = "…" + body.slice(-TG_MAX);
  }

  const plain = tools + thinkingBlock + body + cursor;
  const { html } = markdownToHtml(plain);
  return { content: html, parseMode: "HTML" };
}

