/**
 * 發送或更新 ephemeral draft（Bot API 10.1 sendMessageDraft / sendRichMessageDraft）。
 * 同 draftId 重複呼叫 = 全量替換 + 動畫過渡；空 text = 顯示 "Thinking…"。
 * Draft 是 30s TTL ephemeral，最終須 sendRichMessage/sendMessage 持久化。
 * 僅 private chat 可用；失敗回 false 讓呼叫端走 placeholder fallback。
 */
export async function trySendDraft(
  api: unknown,
  chatId: number,
  draftId: number,
  text: string,
  useRich: boolean,
): Promise<boolean> {
  const raw = (api as { raw?: Record<string, unknown> }).raw;
  if (!raw) return false;

  if (useRich) {
    const method = raw.sendRichMessageDraft;
    if (typeof method !== "function") return false;
    const rich_message = renderTelegramRichDraft(text);
    try {
      await (method as Function).call(raw, {
        chat_id: chatId,
        draft_id: draftId,
        rich_message,
      });
      return true;
    } catch {
      return false;
    }
  }

  // plain draft
  const method = raw.sendMessageDraft;
  if (typeof method !== "function") return false;
  try {
    await (method as Function).call(raw, {
      chat_id: chatId,
      draft_id: draftId,
      text: text || undefined, // undefined → "Thinking…" placeholder
    });
    return true;
  } catch {
    return false;
  }
}

