  // older than this many hours is discarded (not injected, not carried forward)
  // so high-churn sessions (agent switch / restart / idle) stop resurfacing a
  // stale handoff. 0 disables the gate (archive never expires). Default 24h.
  archiveMaxAgeHours:
    Math.max(0, Number(process.env.ARCHIVE_MAX_AGE_HOURS ?? "24")),
  // Enrichment prefix character cap: the dynamic enrichment block prepended
  // to user messages (NotebookLM routing + Wiki + Memory recall + Skill routing
  // + Index retrieval) is capped at this many chars. When exceeded, lower-
  // priority sections are stripped (Index → Memory → Wiki). Default 8000.
  enrichmentPrefixMaxChars:
    Math.max(1000, Number(process.env.ENRICHMENT_PREFIX_MAX_CHARS ?? "8000")),
  tgRichStreamEnabled: (() => {
    const raw = (process.env.TG_RICH_STREAM_ENABLED ?? "1").trim().toLowerCase();
    return raw === "1" || raw === "true" || raw === "yes";
  })(),
  // Bot-to-Bot Relay via Upstash Redis + Telegram bot-to-bot
  relay: (() => {
    const url = (process.env.UPSTASH_REDIS_REST_URL ?? "").trim();
    const token = (process.env.UPSTASH_REDIS_REST_TOKEN ?? "").trim();
    const groupChatId = Number(process.env.RELAY_GROUP_CHAT_ID ?? "0");
    const botName = (process.env.RELAY_BOT_NAME ?? "").trim();
    const transport = (process.env.RELAY_TRANSPORT ?? "redis").trim() as "redis" | "telegram" | "both";
    const targetBotUsername = (process.env.RELAY_TARGET_BOT_USERNAME ?? "").trim();
    // Minimum: need botName + groupChatId + at least one transport configured
    const hasRedis = !!(url && token);
    const hasTelegram = !!targetBotUsername;
    if (!groupChatId || !botName) return null;
    if (!hasRedis && !hasTelegram) return null;
    const maxConsecutiveTurns = Number(process.env.RELAY_MAX_CONSECUTIVE_TURNS) || 3;
    return { redisUrl: url, redisToken: token, groupChatId, botName, maxConsecutiveTurns, transport, targetBotUsername };
  })(),
  // Local LLM feature flags. Set to "0"/"false" to disable.
  localLlmPrefilter: (() => {
    const raw = (process.env.LOCAL_LLM_PREFILTER ?? "1").trim().toLowerCase();
    return raw === "1" || raw === "true" || raw === "yes";
  })(),
  localLlmRerank: (() => {
    const raw = (process.env.LOCAL_LLM_RERANK ?? "1").trim().toLowerCase();
    return raw === "1" || raw === "true" || raw === "yes";
  })(),
  localLlmIntentFallback: (() => {
    const raw = (process.env.LOCAL_LLM_INTENT_FALLBACK ?? "1").trim().toLowerCase();
    return raw === "1" || raw === "true" || raw === "yes";
  })(),
  // RTK (Rust Token Killer) shell rewrite. When enabled, preamble instructs
  // the agent to prefix shell commands with `rtk` for token-compressed output.
  // Requires rtk binary in PATH. Set to "0"/"false" to disable.
  rtkShellRewrite: (() => {
    const raw = (process.env.RTK_SHELL_REWRITE ?? "0").trim().toLowerCase();
    const wanted = raw === "1" || raw === "true" || raw === "yes";
    if (!wanted) return false;
    // Verify rtk is actually reachable
    if (commandExists("rtk")) return true;
    {
      console.warn("[config] RTK_SHELL_REWRITE=1 but `rtk` not found in PATH — disabled");
      return false;
    }
  })(),
  // ─── Multi-Model Provider ─────────────────────────────────────────────────
  /** ACP session resume（方案 A）。預設 off：行為與舊版完全一致。 */
  acpSessionResume: (process.env.ACP_SESSION_RESUME ?? "").trim() === "true",
  // Which provider to use on startup. "acp" = Kiro CLI subprocess (default).
  defaultProvider: (process.env.DEFAULT_PROVIDER ?? "acp").trim().toLowerCase() as ProviderType,
  // Model identifiers per provider (used by DirectProvider, ignored by ACP).
  models: {
    anthropic: (process.env.ANTHROPIC_MODEL ?? "claude-sonnet-4-20250514").trim(),
    openai: (process.env.OPENAI_MODEL ?? "gpt-4o").trim(),
    gemini: (process.env.GEMINI_MODEL ?? "gemini-2.5-flash").trim(),
    deepseek: (process.env.DEEPSEEK_MODEL ?? "deepseek-chat").trim(),
    groq: (process.env.GROQ_MODEL ?? "llama-3.3-70b-versatile").trim(),
    local: (process.env.OLLAMA_CHAT_MODEL ?? "qwen3.6:35b-a3b").trim(),
  },
  // API keys (read at runtime; empty = provider unavailable).
  apiKeys: {
    anthropic: (process.env.ANTHROPIC_API_KEY ?? "").trim(),
    openai: (process.env.OPENAI_API_KEY ?? "").trim(),
    gemini: (process.env.GEMINI_API_KEY ?? "").trim(),
    deepseek: (process.env.DEEPSEEK_API_KEY ?? "").trim(),
    groq: (process.env.GROQ_API_KEY ?? "").trim(),
  },
  // Ollama base URL (also used by DirectProvider "local" mode).
  ollamaUrl: (process.env.OLLAMA_URL ?? "http://127.0.0.1:11434").trim(),
  // llama.cpp server URL. When set, "local" mode uses this instead of Ollama.
  llamaCppUrl: (process.env.LLAMACPP_URL ?? "").trim(),
  // Status monitoring server port.
  statusPort: Number(process.env.STATUS_PORT ?? "3847"),
  // Quiet hours: scheduler skips firing during this window. Format "HH-HH"
  // (24h local time, start inclusive, end exclusive). E.g. "00-08" means
  // 00:00–07:59 is quiet. Recurring schedules re-arm to the end hour;
  // one-shot schedules delay to the end hour. Empty/unset = no quiet hours.
  quietHours: (() => {
    const raw = (process.env.QUIET_HOURS ?? "").trim();
    if (!raw) return null;
    const m = raw.match(/^(\d{1,2})-(\d{1,2})$/);
    if (!m) return null;
    const start = Number(m[1]);
    const end = Number(m[2]);
    if (start < 0 || start > 23 || end < 0 || end > 23 || start === end) return null;
    return { start, end };
  })(),
};

// ─── Bridge Config Path Resolution ──────────────────────────────────────────
// Bridge's own runtime configs (dream.json, specialist-domains.json, etc.)
// are NOT agent-CLI-specific. They live in MEMORY_DIR/config/ (shared) with
// a backward-compatible fallback to AGENT_CONFIG_DIR (old location).
//
// Read: MEMORY_DIR/config/<name> first → fallback AGENT_CONFIG_DIR/<name>
// Write: always MEMORY_DIR/config/<name>

const _bridgeConfigDir = path.join(config.memoryDir, "config");

/**
 * Resolve the path to a bridge config file.
 * Checks MEMORY_DIR/config/<name> first; if not found, falls back to
 * AGENT_CONFIG_DIR/<name> (requires agentConfigDir param since that's
 * detected at runtime by memory.ts).
 *
 * For writes, use `bridgeConfigWritePath(name)` which always points to
 * MEMORY_DIR/config/<name> and ensures the directory exists.
 */
export function resolveBridgeConfigPath(name: string, agentConfigDir: string): string {
  const primary = path.join(_bridgeConfigDir, name);
  if (existsSync(primary)) return primary;
  const fallback = path.join(agentConfigDir, name);
  if (existsSync(fallback)) return fallback;
  // Neither exists — return the primary (new) location for error messages
  return primary;
}

/**
 * Get the write path for a bridge config file. Always MEMORY_DIR/config/<name>.
 * Creates the directory if it doesn't exist.
 */
export function bridgeConfigWritePath(name: string): string {
  if (!existsSync(_bridgeConfigDir)) {
    mkdirSync(_bridgeConfigDir, { recursive: true });
  }
  return path.join(_bridgeConfigDir, name);
}

