import { readFileSync } from "node:fs";
import ts from "typescript";

const source = readFileSync("src/telegram-rich-renderer.ts", "utf8");
const js = ts.transpileModule(source, {
  compilerOptions: {
    module: ts.ModuleKind.ES2022,
    target: ts.ScriptTarget.ES2022,
  },
}).outputText;

const mod = await import(`data:text/javascript;base64,${Buffer.from(js).toString("base64")}`);
const { trySendDraft, trySendRichMessage } = mod;

function assert(name, condition, detail = "") {
  if (!condition) {
    throw new Error(`FAIL: ${name}${detail ? `: ${detail}` : ""}`);
  }
  console.log(`ok - ${name}`);
}

// ─── trySendDraft: plain mode ───

{
  const calls = [];
  const fakeApi = {
    raw: {
      sendMessageDraft: async (params) => { calls.push({ method: "sendMessageDraft", ...params }); return true; },
      sendRichMessageDraft: async (params) => { calls.push({ method: "sendRichMessageDraft", ...params }); return true; },
    },
  };

  // 空 text → "Thinking…" placeholder（text = undefined）
  const ok1 = await trySendDraft(fakeApi, 123, 1, "", false);
  assert("plain draft with empty text returns true", ok1);
  assert("plain draft calls sendMessageDraft", calls[0].method === "sendMessageDraft");
  assert("plain draft sends chat_id", calls[0].chat_id === 123);
  assert("plain draft sends draft_id", calls[0].draft_id === 1);
  assert("plain draft empty text → undefined (Thinking… placeholder)", calls[0].text === undefined);

  // 有 text
  calls.length = 0;
  const ok2 = await trySendDraft(fakeApi, 123, 1, "Hello world", false);
  assert("plain draft with text returns true", ok2);
  assert("plain draft sends text content", calls[0].text === "Hello world");
}

// ─── trySendDraft: rich mode ───

{
  const calls = [];
  const fakeApi = {
    raw: {
      sendRichMessageDraft: async (params) => { calls.push(params); return true; },
    },
  };

  const ok = await trySendDraft(fakeApi, 456, 2, "# Title\nBody", true);
  assert("rich draft returns true", ok);
  assert("rich draft sends chat_id", calls[0].chat_id === 456);
  assert("rich draft sends draft_id", calls[0].draft_id === 2);
  assert("rich draft sends rich_message.markdown", calls[0].rich_message?.markdown === "# Title\nBody");
  assert("rich draft does not send text param", calls[0].text === undefined);
}

// ─── trySendDraft: CRLF 正規化 ───

{
  const calls = [];
  const fakeApi = {
    raw: {
      sendRichMessageDraft: async (params) => { calls.push(params); return true; },
    },
  };

  await trySendDraft(fakeApi, 1, 1, "line1\r\nline2", true);
  assert("rich draft normalizes CRLF", calls[0].rich_message?.markdown === "line1\nline2");
}

// ─── trySendDraft: API 不存在 → false（fallback） ───

{
  const ok1 = await trySendDraft({}, 1, 1, "test", false);
  assert("no raw API returns false (plain)", !ok1);

  const ok2 = await trySendDraft({}, 1, 1, "test", true);
  assert("no raw API returns false (rich)", !ok2);

  const ok3 = await trySendDraft({ raw: {} }, 1, 1, "test", false);
  assert("missing sendMessageDraft returns false", !ok3);

  const ok4 = await trySendDraft({ raw: {} }, 1, 1, "test", true);
  assert("missing sendRichMessageDraft returns false", !ok4);
}

// ─── trySendDraft: API 拋錯 → false（fallback） ───

{
  const fakeApi = {
    raw: {
      sendMessageDraft: async () => { throw new Error("server error"); },
      sendRichMessageDraft: async () => { throw new Error("server error"); },
    },
  };

  const ok1 = await trySendDraft(fakeApi, 1, 1, "test", false);
  assert("plain draft API error returns false", !ok1);

  const ok2 = await trySendDraft(fakeApi, 1, 1, "test", true);
  assert("rich draft API error returns false", !ok2);
}

// ─── trySendDraft: 同 draftId 重複呼叫（模擬全量替換） ───

{
  const calls = [];
  const fakeApi = {
    raw: {
      sendRichMessageDraft: async (params) => { calls.push(params); return true; },
    },
  };

  await trySendDraft(fakeApi, 1, 42, "frame 1", true);
  await trySendDraft(fakeApi, 1, 42, "frame 2 with more", true);
  await trySendDraft(fakeApi, 1, 42, "frame 3 final", true);
  assert("3 frames sent with same draftId", calls.length === 3);
  assert("all frames use same draft_id", calls.every(c => c.draft_id === 42));
  assert("each frame has full content (not appended)", calls[2].rich_message.markdown === "frame 3 final");
}

// ─── trySendRichMessage: final 持久化 ───

{
  const calls = [];
  const fakeApi = {
    raw: {
      sendRichMessage: async (params) => {
        calls.push(params);
        return { message_id: 999 };
      },
    },
  };

  const result = await trySendRichMessage(fakeApi, 1, "Final content", { reply_markup: { inline_keyboard: [] } });
  assert("sendRichMessage returns message_id", result?.message_id === 999);
  assert("sendRichMessage preserves reply_markup", calls[0].reply_markup !== undefined);
  assert("sendRichMessage sends rich_message", calls[0].rich_message?.markdown === "Final content");
}

console.log("\ndraft streaming smoke OK");

